import { Component, HostListener, OnDestroy } from '@angular/core';
import {
  bufferTurn,
  stepSnake,
  type Direction,
  type Point
} from './snake-engine';

const BOARD_SIZE = 14;
const STEP_MS = 140;
const INITIAL_SNAKE: Point[] = [
  { x: 6, y: 7 },
  { x: 5, y: 7 },
  { x: 4, y: 7 }
];
const INITIAL_FOOD: Point = { x: 8, y: 7 };

@Component({
  selector: 'app-root',
  standalone: true,
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnDestroy {
  readonly boardSize = BOARD_SIZE;
  readonly boardIndices = Array.from({ length: BOARD_SIZE }, (_, index) => index);

  snake: Point[] = INITIAL_SNAKE.map((point) => ({ ...point }));
  direction: Direction = 'RIGHT';
  bufferedDirection: Direction | null = null;
  food: Point | null = { ...INITIAL_FOOD };
  isRunning = false;
  isGameOver = false;
  isWon = false;
  score = 0;

  private timerId: ReturnType<typeof setInterval> | null = null;

  get length(): number {
    return this.snake.length;
  }

  get statusLabel(): string {
    if (this.isWon) return 'You win';
    if (this.isGameOver) return 'Game over';
    return this.isRunning ? 'Running' : 'Paused';
  }

  @HostListener('window:keydown', ['$event'])
  onKeydown(event: KeyboardEvent): void {
    const key = String(event.key || '').toLowerCase();

    if (key === ' ') {
      event.preventDefault();
      if (!this.isGameOver && !this.isWon) this.toggleRunning();
      return;
    }

    if (key === 'enter' && (this.isGameOver || this.isWon)) {
      event.preventDefault();
      this.reset();
      return;
    }

    const requested = this.directionFromKey(key);
    if (!requested) return;

    event.preventDefault();
    this.bufferedDirection = bufferTurn(this.direction, this.bufferedDirection, requested);
  }

  toggleRunning(): void {
    if (this.isGameOver || this.isWon) return;
    this.isRunning ? this.pause() : this.start();
  }

  start(): void {
    if (this.isRunning || this.isGameOver || this.isWon) return;
    this.isRunning = true;
    this.clearTimer();
    this.timerId = setInterval(() => this.tick(), STEP_MS);
  }

  pause(): void {
    this.isRunning = false;
    this.clearTimer();
  }

  reset(): void {
    this.clearTimer();
    this.snake = INITIAL_SNAKE.map((point) => ({ ...point }));
    this.direction = 'RIGHT';
    this.bufferedDirection = null;
    this.food = { ...INITIAL_FOOD };
    this.isRunning = false;
    this.isGameOver = false;
    this.isWon = false;
    this.score = 0;
  }

  isSnake(x: number, y: number): boolean {
    return this.snake.some((point) => point.x === x && point.y === y);
  }

  isHead(x: number, y: number): boolean {
    const head = this.snake[0];
    return head.x === x && head.y === y;
  }

  isFood(x: number, y: number): boolean {
    return this.food !== null && this.food.x === x && this.food.y === y;
  }


  ngOnDestroy(): void {
    this.clearTimer();
  }

  private tick(): void {
    if (!this.isRunning || this.isGameOver || this.isWon) return;

    const result = stepSnake({
      snake: this.snake,
      direction: this.direction,
      bufferedDirection: this.bufferedDirection,
      food: this.food,
      score: this.score
    }, this.boardSize);

    this.snake = result.snake;
    this.direction = result.direction;
    this.bufferedDirection = result.bufferedDirection;
    this.food = result.food;
    this.score = result.score;

    if (result.outcome === 'lost') {
      this.isGameOver = true;
      this.pause();
    } else if (result.outcome === 'won') {
      this.isWon = true;
      this.pause();
    }
  }

  private directionFromKey(key: string): Direction | null {
    if (key === 'arrowup' || key === 'w') return 'UP';
    if (key === 'arrowdown' || key === 's') return 'DOWN';
    if (key === 'arrowleft' || key === 'a') return 'LEFT';
    if (key === 'arrowright' || key === 'd') return 'RIGHT';
    return null;
  }

  private clearTimer(): void {
    if (this.timerId !== null) {
      clearInterval(this.timerId);
      this.timerId = null;
    }
  }
}

