export type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';
export type Point = { x: number; y: number };

export interface SnakeSnapshot {
  snake: Point[];
  direction: Direction;
  bufferedDirection: Direction | null;
  food: Point | null;
  score: number;
}

export interface SnakeStep extends SnakeSnapshot {
  outcome: 'moved' | 'lost' | 'won';
}

const DELTA: Record<Direction, Point> = {
  UP: { x: 0, y: -1 },
  DOWN: { x: 0, y: 1 },
  LEFT: { x: -1, y: 0 },
  RIGHT: { x: 1, y: 0 }
};

const OPPOSITE: Record<Direction, Direction> = {
  UP: 'DOWN',
  DOWN: 'UP',
  LEFT: 'RIGHT',
  RIGHT: 'LEFT'
};

function key(point: Point): string {
  return String(point.x) + ',' + String(point.y);
}

export function bufferTurn(
  committed: Direction,
  buffered: Direction | null,
  requested: Direction
): Direction | null {
  if (buffered !== null) return buffered;
  if (requested === committed || OPPOSITE[committed] === requested) return null;
  return requested;
}

export function placeFood(
  snake: Point[],
  boardSize: number,
  random: () => number = Math.random
): Point | null {
  const occupied = new Set(snake.map(key));
  const free: Point[] = [];

  for (let y = 0; y < boardSize; y += 1) {
    for (let x = 0; x < boardSize; x += 1) {
      const point = { x, y };
      if (!occupied.has(key(point))) free.push(point);
    }
  }

  if (free.length === 0) return null;
  const index = Math.min(free.length - 1, Math.floor(random() * free.length));
  return free[index];
}

export function stepSnake(
  state: SnakeSnapshot,
  boardSize: number,
  random: () => number = Math.random
): SnakeStep {
  const direction = state.bufferedDirection ?? state.direction;
  const delta = DELTA[direction];
  const head = state.snake[0];
  const nextHead = { x: head.x + delta.x, y: head.y + delta.y };
  const base = { ...state, direction, bufferedDirection: null };

  if (
    nextHead.x < 0 ||
    nextHead.y < 0 ||
    nextHead.x >= boardSize ||
    nextHead.y >= boardSize
  ) {
    return { ...base, outcome: 'lost' };
  }

  const ateFood = state.food !== null && key(nextHead) === key(state.food);
  const collisionBody = ateFood ? state.snake : state.snake.slice(0, -1);
  if (collisionBody.some((part) => key(part) === key(nextHead))) {
    return { ...base, outcome: 'lost' };
  }

  const snake = [nextHead, ...state.snake];
  if (!ateFood) {
    snake.pop();
    return { ...base, snake, outcome: 'moved' };
  }

  const food = placeFood(snake, boardSize, random);
  return {
    ...base,
    snake,
    food,
    score: state.score + 1,
    outcome: food === null ? 'won' : 'moved'
  };
}
